#include <CL/cl.h>

#define BLOCK_SIZE 16

#define MAX_PD	(3.0e6)
#define PRECISION	0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100
#define FACTOR_CHIP	0.5

const float t_chip = 0.0005f;
const float chip_height = 0.016f;
const float chip_width = 0.016f;
const float amb_temp = 80.0f;

kernel void hotspot(
    int iter,
    const global float* power,
    const global float* temp_in,
    global float* temp_out,
    int col,
    int row,
    int borderCols,
    int borderRows,
    float Cap,
    float Rx,
    float Ry,
    float Rz,
    float step)
{
    int c_start = get_group_id(0) * BLOCK_SIZE;
    int r_start = get_group_id(1) * BLOCK_SIZE;
    int c = get_local_id(0) + c_start;
    int r = get_local_id(1) + r_start;

    if (c >= col || r >= row) return;

    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;
    float Cap_1 = step / Cap;

    float temp_val = temp_in[r * col + c];

    for (int i = 0; i < iter; i++) {
        float delta;

        if ((r == 0) && (c == 0)) {
            delta = Cap_1 * (power[0] +
                (temp_in[1] - temp_in[0]) * Rx_1 +
                (temp_in[col] - temp_in[0]) * Ry_1 +
                (amb_temp - temp_in[0]) * Rz_1);
        }
        else if ((r == 0) && (c == col - 1)) {
            delta = Cap_1 * (power[c] +
                (temp_in[c - 1] - temp_in[c]) * Rx_1 +
                (temp_in[c + col] - temp_in[c]) * Ry_1 +
                (amb_temp - temp_in[c]) * Rz_1);
        }
        else if ((r == row - 1) && (c == col - 1)) {
            delta = Cap_1 * (power[r * col + c] +
                (temp_in[r * col + c - 1] - temp_in[r * col + c]) * Rx_1 +
                (temp_in[(r - 1) * col + c] - temp_in[r * col + c]) * Ry_1 +
                (amb_temp - temp_in[r * col + c]) * Rz_1);
        }
        else if ((r == row - 1) && (c == 0)) {
            delta = Cap_1 * (power[r * col] +
                (temp_in[r * col + 1] - temp_in[r * col]) * Rx_1 +
                (temp_in[(r - 1) * col] - temp_in[r * col]) * Ry_1 +
                (amb_temp - temp_in[r * col]) * Rz_1);
        }
        else if (r == 0) {
            delta = Cap_1 * (power[c] +
                (temp_in[c + 1] + temp_in[c - 1] - 2.0f * temp_in[c]) * Rx_1 +
                (temp_in[col + c] - temp_in[c]) * Ry_1 +
                (amb_temp - temp_in[c]) * Rz_1);
        }
        else if (c == col - 1) {
            delta = Cap_1 * (power[r * col + c] +
                (temp_in[(r + 1) * col + c] + temp_in[(r - 1) * col + c] - 2.0f * temp_in[r * col + c]) * Ry_1 +
                (temp_in[r * col + c - 1] - temp_in[r * col + c]) * Rx_1 +
                (amb_temp - temp_in[r * col + c]) * Rz_1);
        }
        else if (r == row - 1) {
            delta = Cap_1 * (power[r * col + c] +
                (temp_in[r * col + c + 1] + temp_in[r * col + c - 1] - 2.0f * temp_in[r * col + c]) * Rx_1 +
                (temp_in[(r - 1) * col + c] - temp_in[r * col + c]) * Ry_1 +
                (amb_temp - temp_in[r * col + c]) * Rz_1);
        }
        else if (c == 0) {
            delta = Cap_1 * (power[r * col] +
                (temp_in[(r + 1) * col] + temp_in[(r - 1) * col] - 2.0f * temp_in[r * col]) * Ry_1 +
                (temp_in[r * col + 1] - temp_in[r * col]) * Rx_1 +
                (amb_temp - temp_in[r * col]) * Rz_1);
        }
        else {
            delta = Cap_1 * (power[r * col + c] +
                (temp_in[(r + 1) * col + c] + temp_in[(r - 1) * col + c] - 2.0f * temp_in[r * col + c]) * Ry_1 +
                (temp_in[r * col + c + 1] + temp_in[r * col + c - 1] - 2.0f * temp_in[r * col + c]) * Rx_1 +
                (amb_temp - temp_in[r * col + c]) * Rz_1);
        }

        temp_val = temp_val + delta;
    }

    temp_out[r * col + c] = temp_val;
}
